<template><el-card class="card"><h3>设备信息</h3><el-descriptions border :column="3"><el-descriptions-item label="设备名称">{{d.name}}</el-descriptions-item><el-descriptions-item label="生产厂商">{{d.vendor}}</el-descriptions-item><el-descriptions-item label="软件版本">{{d.version}}</el-descriptions-item><el-descriptions-item label="产品型号">{{d.model}}</el-descriptions-item><el-descriptions-item label="序列号">{{d.serial}}</el-descriptions-item></el-descriptions></el-card><el-row :gutter="16"><el-col :span="4" v-for="(v,k) in labels" :key="k"><el-card><div>{{v}}</div><div class="stat">{{c[k]}}</div></el-card></el-col></el-row></template>
<script setup>import{ref,onMounted}from'vue';import{api}from'../api/http';const d=ref({}),c=ref({});const labels={regions:'区域数量',orgs:'组织数量',apps:'应用数量',policies:'策略数量',logs:'日志数量',alerts:'告警数量'};onMounted(async()=>{const r=await api.get('/dashboard');d.value=r.data.device;c.value=r.data.counts})</script>
